import { describe, expect, test } from "bun:test"
import { renderToStaticMarkup } from "react-dom/server"
import Home from "../../app/page"
import { WhyPostQuantum } from "../../components/landing/WhyPostQuantum"

const REQUIRED_CARDS = [
  "Quantum Threat",
  "Account Abstraction",
  "Falcon-512",
  "Hint-Based Verification",
] as const

describe("WhyPostQuantum (RSC)", () => {
  test("renders section with accessible heading linkage", () => {
    const html = renderToStaticMarkup(<WhyPostQuantum />)

    expect(html).toContain('aria-labelledby="why-post-quantum-heading"')
    expect(html).toContain('<h2 id="why-post-quantum-heading"')
    expect(html).toContain("Why Post-Quantum?")
  })

  test("renders exactly four explanation cards with required titles", () => {
    const html = renderToStaticMarkup(<WhyPostQuantum />)
    const cardCount = (html.match(/<article/g) ?? []).length

    expect(cardCount).toBe(4)
    for (const title of REQUIRED_CARDS) {
      expect(html).toContain(title)
    }
  })

  test("uses responsive single-column mobile and two-column desktop layout", () => {
    const html = renderToStaticMarkup(<WhyPostQuantum />)

    expect(html).toContain("grid gap-6 sm:grid-cols-2")
  })

  test("renders as server component markup without inline scripts", () => {
    const html = renderToStaticMarkup(<WhyPostQuantum />)

    expect(html).not.toContain("<script")
  })

  test("is rendered from the landing page", () => {
    const html = renderToStaticMarkup(<Home />)

    expect(html).toContain("Why Post-Quantum?")
    expect(html).toContain("Quantum Threat")
  })
})
